+        assert!(mean < 0.5, "equilibrium mean = {mean}, expected < 0.5");
+    }
+
+    #[test]
+    fn fixed_point_convergence() {
+        // Verify the equilibrium is actually a fixed point: BR(μ*) ≈ μ*.
+        let eq = compute_equilibrium();
