+
+    #[test]
+    fn congestion_count_increments() {
+        let mut ctrl = MeanFieldGameController::new();
+        for _ in 0..2000 {
+            ctrl.observe(500);
+        }
+        for _ in 0..2000 {
+            ctrl.observe(60000);
+        }
+        if matches!(ctrl.state(), MfgState::Congested | MfgState::Collapsed) {
+            assert!(ctrl.congestion_count() > 0);
