+
+    #[test]
+    fn summary_reports_equilibrium_contention() {
+        let ctrl = MeanFieldGameController::new();
+        let s = ctrl.summary();
+        assert!(s.equilibrium_contention > 0.0);
+        assert!(s.equilibrium_contention < 1.0);
+    }
+}

