+mod tests {
+    use super::*;
+
+    #[test]
+    fn starts_calibrating() {
+        let mon = AnytimeEProcessMonitor::new();
+        assert_eq!(
+            mon.state(ApiFamily::PointerValidation),
+            SequentialState::Calibrating
